use std::collections::VecDeque;

struct SensorBuffer {
    data: VecDeque<u16>,
}

impl SensorBuffer {
    fn new() -> Self {
        SensorBuffer { data: VecDeque::new() }
    }

    fn add_reading(&mut self, reading: u16) {
        self.data.push_back(reading);
    }

    fn process_all_readings(&self) -> Result<Vec<u16>, &'static str> {
        if self.data.is_empty() {
            return Err("No data available to process");
        }

        let mut results = Vec::with_capacity(self.data.len());
        for &reading in self.data.iter() {
            results.push(reading * 2);
        }
        Ok(results)
    }
}

fn main() {
    let mut buffer = SensorBuffer::new();
    buffer.add_reading(10);
    buffer.add_reading(25);
    buffer.add_reading(30);

    match buffer.process_all_readings() {
        Ok(processed) => {
            println!("Successfully processed readings: {:?}", processed);
        },
        Err(e) => {
            eprintln!("Error processing data: {}", e);
        }
    }
}

use std::collections::HashMap;
use std::sync::Arc;

struct MessageData {
    payload: String,
}

trait EventHandler: Send + Sync + 'static {
    fn handle(&self, data: &MessageData) -> Result<(), String>;
}

struct ConcreteHandlerA;
impl EventHandler for ConcreteHandlerA {
    fn handle(&self, data: &MessageData) -> Result<(), String> {
        println!("Handling A with payload: {}", data.payload);
        Ok(())
    }
}

struct ConcreteHandlerB;
impl EventHandler for ConcreteHandlerB {
    fn handle(&self, data: &MessageData) -> Result<(), String> {
        println!("Handling B with payload: {}", data.payload);
        Ok(())
    }
}

fn main() -> Result<(), String> {
    let mut registry: HashMap<String, Vec<Arc<dyn EventHandler>>> = HashMap::new();

    let handler_a1: Arc<dyn EventHandler> = Arc::new(ConcreteHandlerA);
    let handler_b1: Arc<dyn EventHandler> = Arc::new(ConcreteHandlerB);

    registry.entry("user_login".to_string()).or_default().push(handler_a1.clone());
    registry.entry("user_logout".to_string()).or_default().push(handler_b1.clone());

    let message = MessageData { payload: "User logged in successfully".to_string() };
    let topic = String::from("user_login");

    if let Some(handlers) = registry.get(&topic) {
        for handler in handlers {
            handler.handle(&message)?;
        }
    }

    Ok(())
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct ChatRoom {
    name: String,
    message_count: usize,
}

struct ChatManager {
    rooms: Mutex<HashMap<String, Arc<Mutex<ChatRoom>>>>
}

impl ChatManager {
    fn new() -> Self {
        ChatManager {
            rooms: Mutex::new(HashMap::new())
        }
    }

    fn get_or_create_room(&self, room_name: &str) -> Arc<Mutex<ChatRoom>> {
        let mut rooms = self.rooms.lock().unwrap();
        if let Some(room) = rooms.get(room_name).cloned() {
            return room;
        }

        let new_room = Arc::new(Mutex::new(ChatRoom { name: room_name.to_string(), message_count: 0 }));
        rooms.insert(room_name.to_string(), new_room.clone());
        new_room
    }

    fn process_message(&self, room_name: &str) -> Result<(), String> {
        let room_mutex = self.get_or_create_room(room_name);
        let mut room = room_mutex.lock().unwrap();
        room.message_count += 1;
        Ok(())
    }
}

use std::collections::VecDeque;

struct DataChunk {}

impl DataChunk {
    fn new() -> Self {
        DataChunk{}
    }
}

fn process_stream<T: std::fmt::Debug>(mut data: VecDeque<Box<T>>) -> String where T: Clone + 'static {
    if data.is_empty() {
        return "No data processed".to_string();
    }

    let first_item = data.pop_front().unwrap();
    println!("Successfully retrieved the initial object instance.");

    let mut results = Vec::new();
    while let Some(next_item) = data.pop_front() {
        results.push(format!("Processed an item of type: {:?}", next_item));
    }

    if !results.is_empty() {
        return format!("Stream processing complete. Total items handled: {}.", results.len());
    } else {
        return "Stream was empty after initial item".to_string();
    }
}

fn main() {
    let mut buffer: VecDeque<Box<i32>> = VecDeque::new();
    buffer.push_back(Box::new(10));
    buffer.push_back(Box::new(25));
    buffer.push_back(Box::new(42));

    let status = process_stream(buffer);
    println!("n[System Status]: {}", status);
}

use core::mem::{self, MaybeUninit};
use std::ptr;

struct DeviceRegisters {
    status: u32,
    data_block1: u32,
    control: u32,
    data_block2: [u8; 4],
}

fn read_device_state(base_addr: usize) -> Option<DeviceRegisters> {
    let status_ptr = base_addr as *const u32;
    let data1_ptr = (base_addr + 0x4) as *const u32;
    let control_ptr = (base_addr + 0x8) as *const u32;
    let data2_ptr = (base_addr + 0xC) as *const [u8; 4];

    if status_ptr.is_null() || data1_ptr.is_null() || control_ptr.is_null() || data2_ptr.is_null() {
        return None;
    }

    let status = unsafe { ptr::read(status_ptr) };
    let data1 = unsafe { ptr::read(data1_ptr) };
    let control = unsafe { ptr::read(control_ptr) };
    let data2 = unsafe { ptr::read(data2_ptr) };

    Some(DeviceRegisters {
        status,
        data_block1: data1,
        control,
        data_block2: data2,
    })
}

fn main() {
    const MOCK_BASE_ADDRESS: usize = 0xDEADBEEF;
    match read_device_state(MOCK_BASE_ADDRESS) {
        Some(regs) => {
            println!("Status Read: 0x{:X}", regs.status);
            println!("Data Block 1: 0x{:X}", regs.data_block1);
            println!("Control Reg: 0x{:X}", regs.control);
            println!("Data Block 2: {:02X?}{:02X?}{:02X?}{:02X?}", regs.data_block2[0], regs.data_block2[1], regs.data_block2[2], regs.data_block2[3]);
        }
        None => {
            eprintln!("Failed to read device registers.");
        }
    }
}
